use serde_json::Value; use std::io::{self,BufRead,Write}; fn main()->anyhow::Result<()> { let stdin=io::stdin(); let mut stdout=io::stdout(); for line in stdin.lock().lines(){ let line=line?; let v:Value=serde_json::from_str(&line).unwrap_or_else(|_| serde_json::json!({"request_id":"unknown"})); let id=v.get("request_id").and_then(|x|x.as_str()).unwrap_or("unknown"); let out=serde_json::json!({"request_id":id,"status":"ok","text":"{\"status\":\"not_found\",\"candidates\":[]}","error_text":None::<String>,"extra":{"action":"resolve_reference"}}); writeln!(stdout,"{}",serde_json::to_string(&out)?)?; stdout.flush()?; } Ok(()) }
